SELECT ?duo ?duoLabel ?song ?songLabel WHERE {
  ?duo wdt:P2591 wd:Q3282557 ;
        wdt:P31 wd:Q16506565 ;
        wdt:P571 ?inception ;
        wdt:P576 ?dissolution .
  FILTER(?inception <= "1969-01-01"^^xsd:date)
  FILTER(?dissolution >= "1974-12-31"^^xsd:date)
  ?duo rdfs:label ?duoLabel .
  FILTER(LANG(?duoLabel) = "en")
  ?song wdt:P170 ?duo .
  ?song rdfs:label ?songLabel .
  FILTER(LANG(?songLabel) = "en")
} LIMIT 1

